5516 // Attempt to narrow a phi of shufflevector instructions where the two incoming
5517 // values have the same operands but different masks. If the two shuffle masks
5518 // are offsets of one another we can use one branch to rotate the incoming
5519 // vector and perform one larger shuffle after the phi.
5520 bool VectorCombine::shrinkPhiOfShuffles(Instruction &I) {
5521   auto *Phi = dyn_cast<PHINode>(&I);
5522   if (!Phi || Phi->getNumIncomingValues() != 2u)
5523     return false;
5524 
5525   Value *Op = nullptr;
5526   ArrayRef<int> Mask0;
5527   ArrayRef<int> Mask1;
5528 
5529   if (!match(Phi->getOperand(0u),
5530              m_OneUse(m_Shuffle(m_Value(Op), m_Poison(), m_Mask(Mask0)))) ||
5531       !match(Phi->getOperand(1u),
5532              m_OneUse(m_Shuffle(m_Specific(Op), m_Poison(), m_Mask(Mask1)))))
5533     return false;
5534 
5535   auto *Shuf = cast<ShuffleVectorInst>(Phi->getOperand(0u));
5536 
5537   // Ensure result vectors are wider than the argument vector.
5538   auto *InputVT = cast<FixedVectorType>(Op->getType());
5539   auto *ResultVT = cast<FixedVectorType>(Shuf->getType());
5540   auto const InputNumElements = InputVT->getNumElements();
5541 
5542   if (InputNumElements >= ResultVT->getNumElements())
5543     return false;
5544 
5545   // Take the difference of the two shuffle masks at each index. Ignore poison
5546   // values at the same index in both masks.
5547   SmallVector<int, 16> NewMask;
5548   NewMask.reserve(Mask0.size());
5549 
5550   for (auto [M0, M1] : zip(Mask0, Mask1)) {
5551     if (M0 >= 0 && M1 >= 0)
5552       NewMask.push_back(M0 - M1);
5553     else if (M0 == -1 && M1 == -1)
5554       continue;
5555     else
5556       return false;
5557   }
5558 
5559   // Ensure all elements of the new mask are equal. If the difference between
5560   // the incoming mask elements is the same, the two must be constant offsets
5561   // of one another.
5562   if (NewMask.empty() || !all_equal(NewMask))
5563     return false;
5564 
5565   // Create new mask using difference of the two incoming masks.
5566   int MaskOffset = NewMask[0u];
5567   unsigned Index = (InputNumElements + MaskOffset) % InputNumElements;
5568   NewMask.clear();
5569 
5570   for (unsigned I = 0u; I < InputNumElements; ++I) {
5571     NewMask.push_back(Index);
5572     Index = (Index + 1u) % InputNumElements;
5573   }
5574 
5575   // Calculate costs for worst cases and compare.
5576   auto const Kind = TTI::SK_PermuteSingleSrc;
5577   auto OldCost =
5578       std::max(TTI.getShuffleCost(Kind, ResultVT, InputVT, Mask0, CostKind),
5579                TTI.getShuffleCost(Kind, ResultVT, InputVT, Mask1, CostKind));
5580   auto NewCost = TTI.getShuffleCost(Kind, InputVT, InputVT, NewMask, CostKind) +
5581                  TTI.getShuffleCost(Kind, ResultVT, InputVT, Mask1, CostKind);
5582 
5583   LLVM_DEBUG(dbgs() << "Found a phi of mergeable shuffles: " << I
5584                     << "\n  OldCost: " << OldCost << " vs NewCost: " << NewCost
5585                     << "\n");
5586 
5587   if (NewCost > OldCost)
5588     return false;
5589 
5590   // Create new shuffles and narrowed phi.
5591   auto Builder = IRBuilder(Shuf);
5592   Builder.SetCurrentDebugLocation(Shuf->getDebugLoc());
5593   auto *PoisonVal = PoisonValue::get(InputVT);
5594   auto *NewShuf0 = Builder.CreateShuffleVector(Op, PoisonVal, NewMask);
5595   Worklist.push(cast<Instruction>(NewShuf0));
5596 
5597   Builder.SetInsertPoint(Phi);
5598   Builder.SetCurrentDebugLocation(Phi->getDebugLoc());
5599   auto *NewPhi = Builder.CreatePHI(NewShuf0->getType(), 2u);
5600   NewPhi->addIncoming(NewShuf0, Phi->getIncomingBlock(0u));
5601   NewPhi->addIncoming(Op, Phi->getIncomingBlock(1u));
5602 
5603   Builder.SetInsertPoint(*NewPhi->getInsertionPointAfterDef());
5604   PoisonVal = PoisonValue::get(NewPhi->getType());
5605   auto *NewShuf1 = Builder.CreateShuffleVector(NewPhi, PoisonVal, Mask1);
5606 
5607   replaceValue(*Phi, *NewShuf1);
5608   return true;
5609 }
